/** Exception class for type errors in Typed Jam. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** Type checker for Typed Jam. Visits an AST with a type environment and returns the Type of each node. */
class TypeChecker implements ASTVisitor<Type> {
  PureList<TypeBinding> env;

  TypeChecker(PureList<TypeBinding> e) { env = e; }

  public Type forBoolConstant(BoolConstant b) { return BoolType.ONLY; }
  public Type forIntConstant(IntConstant i) { return IntType.ONLY; }

  public Type forEmptyConstant(EmptyConstant n) {
    if (n instanceof TypedEmpty) {
      return new ListType(((TypedEmpty) n).type());
    }
    throw new TypeException("Untyped empty is not allowed in Typed Jam");
  }

  public Type forVariable(Variable v) {
    TypeBinding match = env.accept(new LookupVisitor<TypeBinding>(v));
    if (match == null) throw new TypeException("Variable " + v + " has no type binding");
    return match.type();
  }

  public Type forPrimFun(PrimFun f) {
    throw new TypeException("Primitive " + f + " cannot be used as a value in Typed Jam");
  }

  public Type forUnOpApp(UnOpApp u) {
    Type argType = u.arg().accept(this);
    return u.rator().accept(new UnOpTypeChecker(argType));
  }

  public Type forBinOpApp(BinOpApp b) {
    Type type1 = b.arg1().accept(this);
    Type type2 = b.arg2().accept(this);
    return b.rator().accept(new BinOpTypeChecker(type1, type2));
  }

  public Type forApp(App a) {
    AST rator = a.rator();
    AST[] args = a.args();

    // Primitive function applications have polymorphic typing
    if (rator instanceof PrimFun) {
      return checkPrimApp((PrimFun) rator, args);
    }

    // Regular function application
    Type ratorType = rator.accept(this);
    if (!(ratorType instanceof FunType))
      throw new TypeException(rator + " has type " + ratorType + " which is not a function type");
    FunType funType = (FunType) ratorType;

    if (funType.paramTypes().length != args.length)
      throw new TypeException("Function expects " + funType.paramTypes().length +
        " arguments but got " + args.length);

    for (int i = 0; i < args.length; i++) {
      Type argType = args[i].accept(this);
      if (!argType.equals(funType.paramTypes()[i]))
        throw new TypeException("Argument " + (i + 1) + " has type " + argType +
          " but expected " + funType.paramTypes()[i]);
    }
    return funType.returnType();
  }

  /** Type-checks a primitive function application. */
  private Type checkPrimApp(PrimFun prim, final AST[] args) {
    return prim.accept(new PrimFunVisitor<Type>() {
      public Type forConsPrim() {
        if (args.length != 2) throw new TypeException("cons requires 2 arguments");
        Type elemType = args[0].accept(TypeChecker.this);
        Type listType = args[1].accept(TypeChecker.this);
        if (!(listType instanceof ListType))
          throw new TypeException("Second argument to cons must be a list, got " + listType);
        if (!elemType.equals(((ListType) listType).elemType()))
          throw new TypeException("cons element type " + elemType +
            " doesn't match list element type " + ((ListType) listType).elemType());
        return listType;
      }

      public Type forFirstPrim() {
        if (args.length != 1) throw new TypeException("first requires 1 argument");
        Type argType = args[0].accept(TypeChecker.this);
        if (!(argType instanceof ListType))
          throw new TypeException("Argument to first must be a list, got " + argType);
        return ((ListType) argType).elemType();
      }

      public Type forRestPrim() {
        if (args.length != 1) throw new TypeException("rest requires 1 argument");
        Type argType = args[0].accept(TypeChecker.this);
        if (!(argType instanceof ListType))
          throw new TypeException("Argument to rest must be a list, got " + argType);
        return argType;
      }

      public Type forEmptyPPrim() {
        if (args.length != 1) throw new TypeException("empty? requires 1 argument");
        Type argType = args[0].accept(TypeChecker.this);
        if (!(argType instanceof ListType))
          throw new TypeException("Argument to empty? must be a list, got " + argType);
        return BoolType.ONLY;
      }

      public Type forConsPPrim() {
        if (args.length != 1) throw new TypeException("cons? requires 1 argument");
        Type argType = args[0].accept(TypeChecker.this);
        if (!(argType instanceof ListType))
          throw new TypeException("Argument to cons? must be a list, got " + argType);
        return BoolType.ONLY;
      }

      // Eliminated primitives
      public Type forFunctionPPrim() { throw new TypeException("function? is not available in Typed Jam"); }
      public Type forNumberPPrim() { throw new TypeException("number? is not available in Typed Jam"); }
      public Type forListPPrim() { throw new TypeException("list? is not available in Typed Jam"); }
      public Type forRefPPrim() { throw new TypeException("ref? is not available in Typed Jam"); }
      public Type forArityPrim() { throw new TypeException("arity is not available in Typed Jam"); }
    });
  }

  public Type forMap(Map m) {
    Variable[] vars = m.vars();
    Type[] types = m.types();
    PureList<TypeBinding> newEnv = env;
    for (int i = vars.length - 1; i >= 0; i--) {
      newEnv = newEnv.cons(new TypeBinding(vars[i], types[i]));
    }
    Type bodyType = m.body().accept(new TypeChecker(newEnv));
    return new FunType(types, bodyType);
  }

  public Type forIf(If i) {
    Type testType = i.test().accept(this);
    if (!testType.equals(BoolType.ONLY))
      throw new TypeException("If condition has type " + testType + " but expected bool");
    Type conseqType = i.conseq().accept(this);
    Type altType = i.alt().accept(this);
    if (!conseqType.equals(altType))
      throw new TypeException("If branches have different types: " + conseqType + " and " + altType);
    return conseqType;
  }

  public Type forLet(Let l) {
    Def[] defs = l.defs();
    Variable[] vars = l.vars();

    // Build new environment with declared types
    PureList<TypeBinding> newEnv = env;
    for (int i = vars.length - 1; i >= 0; i--) {
      newEnv = newEnv.cons(new TypeBinding(vars[i], defs[i].type()));
    }

    TypeChecker newChecker = new TypeChecker(newEnv);

    // Check that rhs types match declared types
    for (int i = 0; i < defs.length; i++) {
      Type rhsType = defs[i].rhs().accept(newChecker);
      if (!rhsType.equals(defs[i].type()))
        throw new TypeException("Definition of " + vars[i] + " has declared type " +
          defs[i].type() + " but rhs has type " + rhsType);
    }

    return l.body().accept(newChecker);
  }

  public Type forBlock(Block b) {
    AST[] exps = b.exps();
    Type result = null;
    for (int i = 0; i < exps.length; i++) {
      result = exps[i].accept(this);
    }
    return result;
  }

  /** Unary operator type checker. */
  static class UnOpTypeChecker implements UnOpVisitor<Type> {
    Type argType;
    UnOpTypeChecker(Type t) { argType = t; }

    public Type forUnOpPlus() {
      if (!argType.equals(IntType.ONLY))
        throw new TypeException("Unary + requires int but got " + argType);
      return IntType.ONLY;
    }

    public Type forUnOpMinus() {
      if (!argType.equals(IntType.ONLY))
        throw new TypeException("Unary - requires int but got " + argType);
      return IntType.ONLY;
    }

    public Type forOpTilde() {
      if (!argType.equals(BoolType.ONLY))
        throw new TypeException("~ requires bool but got " + argType);
      return BoolType.ONLY;
    }

    public Type forOpBang() {
      if (!(argType instanceof RefType))
        throw new TypeException("! requires ref type but got " + argType);
      return ((RefType) argType).elemType();
    }

    public Type forOpRef() {
      return new RefType(argType);
    }
  }

  /** Binary operator type checker. */
  static class BinOpTypeChecker implements BinOpVisitor<Type> {
    Type type1, type2;
    BinOpTypeChecker(Type t1, Type t2) { type1 = t1; type2 = t2; }

    private void checkBothInt(String op) {
      if (!type1.equals(IntType.ONLY))
        throw new TypeException("Binary " + op + " requires int but left operand is " + type1);
      if (!type2.equals(IntType.ONLY))
        throw new TypeException("Binary " + op + " requires int but right operand is " + type2);
    }

    private void checkBothBool(String op) {
      if (!type1.equals(BoolType.ONLY))
        throw new TypeException("Binary " + op + " requires bool but left operand is " + type1);
      if (!type2.equals(BoolType.ONLY))
        throw new TypeException("Binary " + op + " requires bool but right operand is " + type2);
    }

    public Type forBinOpPlus() { checkBothInt("+"); return IntType.ONLY; }
    public Type forBinOpMinus() { checkBothInt("-"); return IntType.ONLY; }
    public Type forOpTimes() { checkBothInt("*"); return IntType.ONLY; }
    public Type forOpDivide() { checkBothInt("/"); return IntType.ONLY; }

    public Type forOpLessThan() { checkBothInt("<"); return BoolType.ONLY; }
    public Type forOpGreaterThan() { checkBothInt(">"); return BoolType.ONLY; }
    public Type forOpLessThanEquals() { checkBothInt("<="); return BoolType.ONLY; }
    public Type forOpGreaterThanEquals() { checkBothInt(">="); return BoolType.ONLY; }

    public Type forOpAnd() { checkBothBool("&"); return BoolType.ONLY; }
    public Type forOpOr() { checkBothBool("|"); return BoolType.ONLY; }

    public Type forOpEquals() {
      if (!type1.equals(type2))
        throw new TypeException("= requires same types but got " + type1 + " and " + type2);
      return BoolType.ONLY;
    }

    public Type forOpNotEquals() {
      if (!type1.equals(type2))
        throw new TypeException("!= requires same types but got " + type1 + " and " + type2);
      return BoolType.ONLY;
    }

    public Type forOpGets() {
      if (!(type1 instanceof RefType))
        throw new TypeException("<- requires ref type on left but got " + type1);
      if (!((RefType) type1).elemType().equals(type2))
        throw new TypeException("<- type mismatch: ref holds " + ((RefType) type1).elemType() + " but assigning " + type2);
      return UnitType.ONLY;
    }
  }
}
